import type { RcTriggerPropsWithRef } from '../types';

export const useTriggerDisabled = (
  props: RcTriggerPropsWithRef,
  config: { disabled: boolean },
): [RcTriggerPropsWithRef] => {
  const { disabled } = config;
  const { action, hideAction, showAction } = props;

  const mergedAction = disabled ? [] : action;
  const mergedshowAction = disabled ? [] : showAction;
  const mergedHideAction = disabled ? [] : hideAction;

  return [
    {
      ...props,
      action: mergedAction,
      showAction: mergedshowAction,
      hideAction: mergedHideAction,
    },
  ];
};
